&Total = 0
&Count = 0
&Percentual = 0
&ProgressIni = serverNow()
do 'Atualiza'

//CAPA ORDEM PRODUCAO
For Each Order EmpCod, FilCod, OrdCod
	Where EmpCod = &EmpCod
	Where FilCod = &FilCod
	Where OrdCod = &OrdCod

	&OrdTip = OrdTip

	OrdDta = serverdate()
	OrdSts = Status_Producao.EmProducao

	//ENTRADA PRODUCAO
	UltimoCodigoEmpresa.Call(domParCod.PEDIDO, EmpCod, FilCod, &OrdEntPedCod)
	OrdEntPedCod = &OrdEntPedCod

	//SAIDA MATERIAPRIMA
//	UltimoCodigoEmpresa.Call(domParCod.PEDIDO, EmpCod, FilCod, &OrdSaiPedCod)
//	OrdSaiPedCod = &OrdSaiPedCod

	Exit
EndFor

commit 

&Percentual = 5
do 'Atualiza'

If &OrdTip = TipoOrdem.CancelamentoProducao
	RetornaConfSistema.Call(&EmpCod, &FilCod, domConfSistema.TCon049_TipoLctoCancelaProducao, &CfgVlr)
	&LctCod = val(&CfgVlr)
Else	
	//GRAVA ENTRADA PRODUCAO
	RetornaConfSistema.Call(&EmpCod, &FilCod, domConfSistema.TCon037_tipLctoOrdemProducao, &CfgVlr)
	&LctCod = val(&CfgVlr)
EndIF

For Each Order EmpCod, FilCod
	Where EmpCod = &EmpCod
	Where FilCod = &FilCod
	&FilPesCod = FilPesCod
	&FilTabCod = FilTabCod
	Exit
EndFor

For Each Order EmpCod, FilCod, PedCod
	Where EmpCod = &EmpCod
	Where FilCod = &FilCod
	Where PedCod = &OrdEntPedCod

    LctCod = &LctCod
    PedCliCod = &FilPesCod
    PedVenCod = 1
    PedDtaEms = serverdate()
    PedHorEms = serverTime()
    TabCod = &FilTabCod
    TabColCod = 1
	PedPraCod = 1
    PedPraParNom = ''
    PedTraRedCod = 1
    PedTraSaiCod = 1
    //PedObsGer = 'ORDEM 
    PedVlrFrt = 0             

    //PedDtaSep = NullValue(PedDtaSep)  
    //PedDtaDsp    = NullValue(PedDtaDsp) 
    //PedDtaPrv    = NullValue(PedDtaPrv) 
    PedTipFrt = TipoFrete.SEMFRETE
	PedSts = Status_Pedido.ABERTO
    //PedDtaFat = serverdate()
	PedStsGer = Pedido_Gerado.Interno
	PedStsFin = Status_Financeiro.ABERTO

	&Percentual = 7
	do 'Atualiza'

	For Each Order EmpCod, FilCod, PedCod, PedItmCod
		delete
	EndFor

	&Percentual = 15
	do 'Atualiza'
When none
	New
		EmpCod = &EmpCod
	    FilCod = &FilCod
	    PedCod = &OrdEntPedCod
	    LctCod = &LctCod
	    PedCliCod = &FilPesCod
	    PedVenCod = 1
	    PedDtaEms = serverdate()
	    PedHorEms = serverTime()
	    TabCod = &FilTabCod
	    TabColCod = 1
	    PedPraCod = 1
	    PedPraParNom = ''
	    PedTraRedCod = 1
	    PedTraSaiCod = 1
	    //PedObsGer = &PedObs
		PedBlq = Status_SimNao.Sim
	    PedVlrFrt = 0             
	    PedVlrGnre = 0
		PedVlrIpi = 0
	    //PedDtaSep = NullValue(PedDtaSep)  
	    //PedDtaDsp    = NullValue(PedDtaDsp) 
	    //PedDtaPrv    = NullValue(PedDtaPrv) 
	    PedTipFrt = TipoFrete.SEMFRETE
		PedSts = Status_Pedido.ABERTO
	    //PedDtaFat = serverdate()
		PedStsFin = Status_Financeiro.ABERTO
		PedStsGer = Pedido_Gerado.Interno

	EndNew

	&Percentual = 15
	do 'Atualiza'
	CriticasPedido.Call(&EmpCod, &FilCod, &OrdEntPedCod, TipoCriticaPedido.Digitado, &PesCod)
EndFor

commit 

For Each Order EmpCod, FilCod, OrdCod, OrdProCod
	Where EmpCod = &EmpCod
	Where FilCod = &FilCod
	Where OrdCod = &OrdCod


	if &ORdTip = TipoOrdem.CancelamentoProducao
		GravaCancelar.Call(EmpCod, FilCod, OrdProCod, OrdProGraCod, 0, &EstDias)
	Else
		GravarFabricar.Call(EmpCod, FilCod, OrdProCod, OrdProGraCod, 0, &EstDias)
	EndIF

	if OrdProQtd > 0 or OrdProQtdSem > 0
		New
			EmpCod = &EmpCod
			FilCod = &FilCod
			PedCod = &OrdEntPedCod
			PedItmCod = OrdItmCod
			ProCod    = OrdProCod
			ProGraCod = OrdProGraCod
			PedQtd    = (OrdProQtd + OrdProQtdSem)
			PedQtdEmb = (OrdProQtd + OrdProQtdSem)
			PedVlrUnt = OrdProVlrCus
			PedVlrCus = OrdProVlrCus
			PedVlrCusPrd    = 0
			PedProEstProCod = OrdProCod
			PedProEstProGraCod = OrdProGraCod
		EndNew
	Endif

EndFor

commit

&Percentual = 30
do 'Atualiza'

if &ORdTip = TipoOrdem.CancelamentoProducao	
	RetornaConfSistema.Call(&EmpCod, &FilCod, domConfSistema.TCon050_TipoLctoExtMatPrima, &CfgVlr)
	&LctCod = val(&CfgVlr)
Else	
	//GRAVA SAIDA MATERIA PRIMA
	RetornaConfSistema.Call(&EmpCod, &FilCod, domConfSistema.TCon036_TipLctoBaixaMateriaPrima, &CfgVlr)
	&LctCod = val(&CfgVlr)
EndIF

For Each Order EmpCod, FilCod
	Where EmpCod = &EmpCod
	Where FilCod = &FilCod
	&FilPesCod = FilPesCod
	&FilTabCod = FilTabCod
	Exit
EndFor

if Not &OrdEntPedCod.IsEmpty()
	AtualizaTotaisPedido.Call(&EmpCod, &FilCod, &OrdEntPedCod, 0, 'C')
Endif

